level = 44
bgm = hideout
margin = 1
roof = wood
shadow = dark
sky = black
blank = rock
outfield = soil
antiWarp = true

; パーツ画像
━ = plasterp
　 = wood
／ = door
〆 = heart
① = ladderu
㊤ = ladderu
㊦ = ladderd
⑺ = barrel

; 敵情報
